// Define the targets you want to watch.
// Return ONE item per URL so the HTTP Request node fetches each one separately.
// Edit this list: add/remove objects, change the "label" (shown in alerts) and "url".
const targets = [
  { label: 'Example Homepage', url: 'https://example.com' },
  { label: 'Example Pricing',  url: 'https://example.com/pricing' },
  { label: 'Example Status',   url: 'https://example.com/status' },
];

return targets.map((t) => ({ json: { label: t.label, url: t.url } }));

// Compares each freshly fetched page against the last version we saw and
// emits an alert item ONLY when a site is down or its content changed.
//
// State is persisted in workflow static data ('global'), keyed by URL, so it
// survives between executions without any database. On the very first run a
// URL has no stored baseline yet -> we record it and stay silent (no alert).

const staticData = $getWorkflowStaticData('global');
// Namespaced bucket so we never collide with other workflow state.
if (!staticData.siteMonitor) staticData.siteMonitor = {};
const store = staticData.siteMonitor;

// Cheap, dependency-free signature of a page body. We combine length with a
// rolling 32-bit hash so unrelated edits of equal length still differ.
function signature(text) {
  const s = String(text == null ? '' : text);
  let hash = 0;
  for (let i = 0; i < s.length; i++) {
    hash = (hash * 31 + s.charCodeAt(i)) | 0; // | 0 keeps it a 32-bit int
  }
  return s.length + ':' + (hash >>> 0).toString(16);
}

const alerts = [];

for (const item of $input.all()) {
  const data = item.json || {};
  // 'url' / 'label' were carried through from the target item; the HTTP node
  // (fullResponse) adds statusCode + body. A network failure leaves them blank.
  const url = data.url || data.requestUrl || '';
  const label = data.label || url || 'Unknown target';
  const statusCode = typeof data.statusCode === 'number' ? data.statusCode : null;
  const body = data.body !== undefined ? data.body : data.data;

  // Treat a missing/error status or any 4xx/5xx as "down".
  const isDown = statusCode === null || statusCode >= 400;

  const prev = store[url];
  const newSig = isDown ? null : signature(body);

  let changeType = 'ok';
  let message = '';

  if (isDown) {
    changeType = 'down';
    const codeText = statusCode === null ? 'no response' : 'HTTP ' + statusCode;
    message = ':rotating_light: ' + label + ' is DOWN (' + codeText + ') — ' + url;
  } else if (!prev || prev.signature == null) {
    // First time we successfully see this URL: record baseline, stay silent.
    changeType = 'baseline';
  } else if (prev.signature !== newSig) {
    changeType = 'changed';
    message = ':eyes: Content changed on ' + label + ' (' + url + ')';
  } else if (prev.lastStatus === 'down') {
    // Recovery: it was down before and is healthy now — worth a heads-up.
    changeType = 'recovered';
    message = ':white_check_mark: ' + label + ' is back UP (HTTP ' + statusCode + ') — ' + url;
  }

  // Always update state so the next run compares against the latest version.
  store[url] = {
    signature: newSig,
    lastStatus: isDown ? 'down' : 'ok',
    statusCode: statusCode,
    lastCheckedAt: new Date().toISOString(),
  };

  if (changeType === 'down' || changeType === 'changed' || changeType === 'recovered') {
    alerts.push({
      json: { label, url, statusCode, changeType, message },
    });
  }
}

// Returning an empty array means the workflow simply stops here on a quiet run,
// so no Slack message is sent unless something actually happened.
return alerts;
